#include <stdio.h>
int main() {
    int T, N, S, Q;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &S, &Q);
        int ans[N];
        ans[S - 1] = Q;
        int diff = (N + 1) / 2;
        for (int i = S - 2; i >= 0; i--) {
            ans[i] = ans[i + 1] - diff;
            if (ans[i] < 1) ans[i] = 1;
        }
        for (int i = S; i < N; i++) {
            ans[i] = ans[i - 1] + diff;
            if (ans[i] > N) ans[i] = N;
        }
        int max_diff = 0;
        for (int i = 0; i < N - 1; i++) {
            max_diff = (max_diff > abs(ans[i] - ans[i + 1])) ? max_diff : abs(ans[i] - ans[i + 1]);
        }
        printf("%d\n", max_diff);
        for (int i = 0; i < N; i++) {
            printf("%d ", ans[i]);
        }
        printf("\n");
    }
    return 0;
}

