import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int S = sc.nextInt();
            int Q = sc.nextInt();
            int[] ans = new int[N];
            ans[S - 1] = Q;
            int diff = (N + 1) / 2;
            for (int i = S - 2; i >= 0; i--) {
                ans[i] = ans[i + 1] - diff;
                if (ans[i] < 1) ans[i] = 1;
            }
            for (int i = S; i < N; i++) {
                ans[i] = ans[i - 1] + diff;
                if (ans[i] > N) ans[i] = N;
            }
            int max_diff = 0;
            for (int i = 0; i < N - 1; i++) {
                max_diff = (max_diff > Math.abs(ans[i] - ans[i + 1])) ? max_diff : Math.abs(ans[i] - ans[i + 1]);
            }
            System.out.println(max_diff);
            for (int i = 0; i < N; i++) {
                System.out.print(ans[i] + " ");
            }
            System.out.println();
        }
    }
}

